async def _load_manage_user(*, request: Request, gateway_proxy: JavaGatewayProxyClient) -> dict[str, Any]:
    authorization = _get_authorization(request)
    if not authorization:
        raise HTTPException(status_code=401, detail="missing authorization")
    payload = await _call_gateway_json(
        gateway_proxy=gateway_proxy,
        authorization=authorization,
        method="GET",
        path="/common/currentUserInfo",
    )
    user = payload.get("data") if isinstance(payload, dict) and payload.get("code") == 200 else None
    if not isinstance(user, dict):
        raise HTTPException(status_code=401, detail="manage auth rejected")
    role_permissions = user.get("rolePermission")
    has_admin_role = isinstance(role_permissions, list) and any(str(item).strip() == "admin" for item in role_permissions)
    has_debug_privilege = int(user.get("debugPrivilege") or 0) == 1
    if not has_admin_role and not has_debug_privilege:
        raise HTTPException(status_code=403, detail="manage permission denied")
    return user


