async def _call_gateway_json(
    *,
    gateway_proxy: JavaGatewayProxyClient,
    authorization: str,
    method: str,
    path: str,
    query_string: str = "",
    json_payload: dict[str, Any] | None = None,
) -> dict[str, Any]:
    try:
        response = await gateway_proxy.request(
            method=method,
            path=path,
            query_string=query_string,
            headers=(
                ("Authorization", authorization),
                ("Content-Type", "application/json"),
            ),
            content=json.dumps(json_payload, ensure_ascii=False).encode("utf-8") if json_payload is not None else None,
        )
    except Exception as exc:  # noqa: BLE001
        raise HTTPException(status_code=502, detail=f"manage gateway request failed: {exc}") from exc
    if response.status_code >= 400:
        raise HTTPException(status_code=response.status_code, detail=f"manage gateway rejected: {response.text[:300]}")
    try:
        return response.json()
    except ValueError as exc:
        raise HTTPException(status_code=502, detail="manage gateway returned non-json response") from exc


def _get_authorization(request: Request) -> str:
    return (request.headers.get("Authorization") or "").strip()


def _build_replay_turns(events: list[dict[str, Any]]) -> list[dict[str, Any]]:
    turns: list[dict[str, Any]] = []
    current_turn: dict[str, Any] | None = None
    misc_events: list[dict[str, Any]] = []

    for event in events:
        projected = _project_event_item(event)
        if projected["event_type"] == "user_message":
            current_turn = {
                "turn_index": len(turns) + 1,
                "anchor_event_id": projected["id"],
                "query": _clean(projected["data"].get("query")),
                "status": "running",
                "events": [projected],
                "assistant_message_event_id": None,
                "assistant_preview": None,
            }
            turns.append(current_turn)
            continue

        if current_turn is None:
            misc_events.append(projected)
            continue

        current_turn["events"].append(projected)
        if projected["event_type"] == "final":
            current_turn["status"] = "final"
            current_turn["assistant_message_event_id"] = projected["id"]
            current_turn["assistant_preview"] = _clean(projected["data"].get("answer"))
        elif projected["event_type"] == "clarification_needed":
            current_turn["status"] = "clarify"
            current_turn["assistant_message_event_id"] = projected["id"]
            current_turn["assistant_preview"] = _clean(projected["data"].get("question"))
        elif projected["event_type"] == "conversation_failed":
            current_turn["status"] = "failed"
            current_turn["assistant_message_event_id"] = projected["id"]
            current_turn["assistant_preview"] = _clean(projected["data"].get("error"))

    if misc_events:
        turns.insert(
            0,
            {
                "turn_index": 0,
                "anchor_event_id": 0,
                "query": None,
                "status": "system",
                "events": misc_events,
                "assistant_message_event_id": None,
                "assistant_preview": None,
            },
        )
    for turn in turns:
        turn["event_count"] = len(turn["events"])
    return turns


def _build_timeline_messages(turns: list[dict[str, Any]]) -> list[dict[str, Any]]:
    messages: list[dict[str, Any]] = []
    for turn in turns:
        turn_index = int(turn.get("turn_index") or 0)
        query = _clean(turn.get("query"))
        if query:
            messages.append(
                {
                    "message_id": turn.get("anchor_event_id"),
                    "turn_index": turn_index,
                    "role": "user",
                    "content": query,
                    "created_at": _first_event_time(turn.get("events") or []),
                    "status": "user",
                    "anchor_event_id": turn.get("anchor_event_id"),
                }
            )
        assistant_message = _project_assistant_message(turn)
        if assistant_message is not None:
            messages.append(assistant_message)
    return messages


def _project_assistant_message(turn: dict[str, Any]) -> dict[str, Any] | None:
    for event in turn.get("events") or []:
        event_type = event.get("event_type")
        if event_type == "final":
            return {
                "message_id": event.get("id"),
                "turn_index": turn.get("turn_index"),
                "role": "assistant",
                "content": _clean(event.get("data", {}).get("answer")) or "",
                "created_at": event.get("created_at"),
                "status": "final",
                "anchor_event_id": turn.get("anchor_event_id"),
            }
        if event_type == "clarification_needed":
            return {
                "message_id": event.get("id"),
