def _first_event_time(events: list[dict[str, Any]]) -> Any:
    return events[0].get("created_at") if events else None


def _project_event_item(event: dict[str, Any]) -> dict[str, Any]:
    data = event.get("data")
    normalized_data = data if isinstance(data, dict) else {}
    return {
        "id": event.get("id"),
        "conversation_id": event.get("conversationId"),
        "event_type": _clean(event.get("eventType")),
        "visible_in_messages": bool(event.get("visibleInMessages")),
        "include_in_context": bool(event.get("includeInContext")),
        "created_at": event.get("createdAt"),
        "summary": _summarize_event(_clean(event.get("eventType")), normalized_data),
        "data": normalized_data,
        "raw_json": json.dumps(normalized_data, ensure_ascii=False, default=str, indent=2),
    }


def _summarize_event(event_type: str, data: dict[str, Any]) -> str:
    if event_type == "user_message":
        return _truncate(_clean(data.get("query")), 120) or "user_message"
    if event_type == "final":
        return _truncate(_clean(data.get("answer")), 120) or "final"
    if event_type == "clarification_needed":
        return _truncate(_clean(data.get("question")), 120) or "clarification_needed"
    if event_type == "conversation_failed":
        return _truncate(_clean(data.get("error")), 120) or "conversation_failed"
    if event_type == "tool_call":
        return f"{_clean(data.get('name')) or 'tool'}({_truncate(_json_inline(data.get('arguments')), 80)})"
    if event_type == "tool_result":
        return _truncate(_clean(data.get("preview")), 120) or _clean(data.get("name")) or "tool_result"
    if event_type == "llm_request":
        request = data.get("request")
        if isinstance(request, dict):
            return f"{_clean(data.get('mode')) or 'llm'} request"
    if event_type == "llm_response":
        return _truncate(_clean(data.get("content")), 120) or f"{_clean(data.get('mode')) or 'llm'} response"
    if event_type == "react_plan":
        return _truncate(_json_inline(data), 120)
    return _truncate(_json_inline(data), 120)


def _resolve_static_dir() -> Path:
    return Path(__file__).resolve().parent / "static" / "manage-console"


def _clean(value: Any) -> str | None:
    if value is None:
        return None
    text = str(value).strip()
    return text or None


def _truncate(value: str | None, max_len: int) -> str:
    text = value or ""
    return text if len(text) <= max_len else f"{text[: max_len - 3]}..."


def _json_inline(value: Any) -> str:
    try:
        return json.dumps(value, ensure_ascii=False, default=str)
    except Exception:  # noqa: BLE001
        return str(value)

